spring.application.name=SemurbSystem
spring.threads.virtual.enabled=true

spring.profiles.active=prod

spring.jpa.properties.hibernate.jdbc.time_zone=UTC

spring.web.locale=pt_BR
spring.web.locale-resolver=fixed

spring.messages.basename=messages
spring.messages.encoding=UTF-8

app.security.default-password=${DEFAULT_PASSWORD}

app.security.cookie.secure=${COOKIE_SECURE:true}

##Em producao, deve ser 'true' se estiver usando HTTPS
server.servlet.session.cookie.secure=${COOKIE_SECURE:true}

## Desabilitado para evitar esgotamento de conex�es sob carga (anti-pattern OSIV)
spring.jpa.open-in-view=false

server.port=8080

server.servlet.session.timeout=1h
server.servlet.session.cookie.max-age=1h

# Configuracoes de Email (Brevo API)
email.brevo.api-key=${BREVO_API_KEY}
email.from=${EMAIL_FROM}
email.from-name=${EMAIL_FROM_NAME}

# URL do Frontend (para links de ativacao de conta)
app.frontend.url=${FRONTEND_URL}

# Cloudflare R2 (storage de imagens de perfil)-
storage.r2.enabled=${R2_ENABLED:false}
storage.r2.account-id=${R2_ACCOUNT_ID}
storage.r2.access-key=${R2_ACCESS_KEY:${R2_ACCESS_KEY_ID}}
storage.r2.secret-key=${R2_SECRET_KEY}
storage.r2.bucket=${R2_BUCKET}
storage.r2.public-base-url=${R2_PUBLIC_BASE_URL}
storage.r2.presigned-url-duration-minutes=${R2_PRESIGNED_URL_DURATION_MINUTES}
storage.r2.max-file-size-bytes=${R2_MAX_FILE_SIZE_BYTES}

# Upload de arquivos (multipart)
spring.servlet.multipart.max-file-size=10MB
spring.servlet.multipart.max-request-size=12MB

# Compressao gzip nas respostas HTTP (reduz 70-85% da banda em JSON)
server.compression.enabled=true
server.compression.mime-types=application/json,application/xml,text/html,text/plain,text/css,application/javascript
server.compression.min-response-size=1024

# Bootstrap do sistema (setup inicial - so executa com banco vazio)
# Apos o primeiro setup, pode remover ou deixar - e ignorado se ja existir usuario
admin.name=${BOOTSTRAP_ADMIN_NAME}
admin.email=${BOOTSTRAP_ADMIN_EMAIL}
admin.password=${BOOTSTRAP_ADMIN_PASSWORD}

app.cors.allowed-origins=${ALLOWED_ORIGINS:https://sonar-fawn.vercel.app}

# Integra??o com o Sistema de Tickets
ticket-system.base-url=${TICKET_SYSTEM_BASE_URL:}
ticket-system.client-id=${TICKET_CLIENT_ID:}
ticket-system.client-secret=${TICKET_CLIENT_SECRET:}
ticket-system.webhook-secret=${TICKET_WEBHOOK_SECRET:}
---PROD---
spring.datasource.url=${BD_URL_PROD}
spring.datasource.username=${BD_USER_PROD}
spring.datasource.password=${BD_PASS_PROD}

spring.datasource.driver-class-name=org.postgresql.Driver

spring.jpa.show-sql=false

springdoc.api-docs.enabled=false
springdoc.swagger-ui.enabled=false

#exclui valores null nos retorno de GET no JSON
#spring.jackson.default-property-inclusion=non_null

spring.flyway.enabled=true

#logging.level.org.springframework.core.env=DEBUG

app.cors.allowed-origins=http://localhost:1405,http://localhost:3000,http://localhost:8080,http://127.0.0.1:3000,https://sonar-fawn.vercel.app

# nunca expor mensagem de erro ou stacktrace do servidor ao cliente
server.error.include-message=never
server.error.include-stacktrace=never
server.error.include-binding-errors=never

# garantir que DevTools está desabilitado em produção
spring.devtools.restart.enabled=false
spring.devtools.livereload.enabled=false
spring.devtools.add-properties=false
---DEV---
spring.datasource.url=${BD_URL_DEV}
spring.datasource.username=${BD_USER_DEV}
spring.datasource.password=${BD_PASS_DEV}

spring.datasource.driver-class-name=org.postgresql.Driver

spring.devtools.restart.enabled=false

spring.jpa.show-sql=true

#exclui valores null nos retorno de GET no JSON
#spring.jackson.default-property-inclusion=non_null

#spring.flyway.baseline-on-migrate=true
spring.flyway.enabled=true

#logging.level.org.springframework.core.env=DEBUG

app.cors.allowed-origins=http://localhost:1405,http://localhost:3000,http://localhost:8080,http://127.0.0.1:3000,https://sonar-fawn.vercel.app

